import { useEffect, useState } from "react";
import { PageShell } from "@/components/orderly/PageShell";
import { OdsCheckbox } from "@/components/orderly/OdsCheckbox";
import { ShieldAlert, X } from "lucide-react";
import { useTranslation } from "@/i18n";
import { storageKey } from "@/utils/storage";

export default function ServiceDisclaimerPage() {
  const { t } = useTranslation();
  const [enabled, setEnabled] = useState<boolean>(false);
  const [toast, setToast] = useState<string | null>(null);

  useEffect(() => {
    setEnabled(
      localStorage.getItem(storageKey("orderlyServiceDisclaimer")) === "true"
    );
  }, []);

  function showToast(message: string) {
    setToast(message);
    setTimeout(() => setToast(null), 3000);
  }

  function handleToggle(checked: boolean) {
    setEnabled(checked);
    localStorage.setItem(
      storageKey("orderlyServiceDisclaimer"),
      String(checked)
    );
    showToast(
      checked ? t("serviceDisclaimer.enabled") : t("serviceDisclaimer.disabled")
    );
  }

  return (
    <PageShell pageTitle="Service disclaimer">
      <div className="space-y-5">
        <div className="rounded-xl border border-(--line-subtle) bg-(--bg-surface-primary) p-6">
          <div className="mb-5 flex items-center gap-2">
            <div className="flex h-8 w-8 items-center justify-center rounded-md bg-[rgba(255,99,144,0.12)] text-[#FF6390]">
              <ShieldAlert className="h-4 w-4" />
            </div>
          </div>

          <div className="mb-5 flex items-start gap-3 rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
            <OdsCheckbox
              id="enableServiceDisclaimer"
              checked={enabled}
              onCheckedChange={checked => handleToggle(checked === true)}
              className="mt-1"
            />
            <div className="flex-1">
              <label
                htmlFor="enableServiceDisclaimer"
                className="cursor-pointer text-sm font-medium text-(--fg-primary)"
              >
                Enable service disclaimer dialog
              </label>
              <p className="mt-0.5 text-xs text-(--fg-secondary)">
                Show a disclaimer dialog to users before they access trading
                features.
              </p>
            </div>
          </div>

          <div className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4">
            <div className="mb-3 text-xs font-medium text-(--fg-secondary)">
              Preview:
            </div>
            <p className="mb-3 text-xs text-(--fg-secondary)">
              When enabled, users will see the following dialog on their first
              visit:
            </p>
            <div className="rounded-lg border border-(--line-subtle) bg-(--bg-input) p-4">
              <div className="mb-3 flex items-center justify-between">
                <p className="text-sm font-medium text-(--fg-primary)">
                  Service disclaimer
                </p>
                <button
                  type="button"
                  className="text-(--fg-secondary) transition-colors hover:text-(--fg-primary)"
                >
                  <X className="h-4 w-4" />
                </button>
              </div>
              <p className="mb-3 text-sm text-(--fg-secondary)">
                This platform uses Orderly Network infrastructure. By
                proceeding, you acknowledge that you understand the risks
                associated with decentralized trading.
              </p>
              <p className="mb-4 text-xs text-(--fg-secondary)">
                By clicking Agree, you confirm that you have read and understood
                this disclaimer.
              </p>
              <div className="flex justify-end gap-2">
                <button
                  type="button"
                  className="rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) px-4 py-2 text-xs font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
                >
                  Disagree
                </button>
                <button
                  type="button"
                  className="rounded-full px-4 py-2 text-xs font-medium text-(--fg-primary) transition-opacity hover:opacity-90"
                  style={{ background: "var(--bg-brand-grad)" }}
                >
                  Agree
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {toast && (
        <div className="fixed bottom-5 left-1/2 z-100 -translate-x-1/2 rounded-full border border-(--line-brand) bg-(--bg-surface-primary) px-5 py-2.5 text-sm font-medium text-(--fg-primary) shadow-xl">
          {toast}
        </div>
      )}
    </PageShell>
  );
}
